/*
 * Normalize a Vagaro appointment webhook into { appointment_id } for
 * POST /webhooks/appointment-cancelled, forwarding only CANCELLATIONS.
 *
 * Confirmed envelope (docs.vagaro.com, Jul 2026):
 *   { id, createdDate, type: "appointment", action: "created"|"updated"|"deleted",
 *     payload: { appointmentId, bookingStatus, startTime, serviceTitle, ... } }
 * A cancellation is signalled by payload.bookingStatus === "Cancel"
 * (action is typically "updated" or "deleted"). Vagaro webhook support is
 * PLAN-DEPENDENT and payload keys have varied across accounts, so we parse the
 * envelope defensively and fall back across several key spellings.
 *
 * ⚠️  CRITICAL: payload.appointmentId is Vagaro's INTERNAL id — a base64 string
 *     like "2dwfErtmMAFxe6hoCnQStw==". It is NOT our Supabase appointments.id
 *     (a UUID). We forward it as-is, so the backend will currently respond 404
 *     ("appointment not found"). A Vagaro-id -> appointments.id lookup/mapping
 *     must be added (here or in the backend) BEFORE this workflow goes live.
 */
const out = [];
for (const entry of $input.all()) {
  const raw = (entry.json && entry.json.body) || entry.json || {};   // webhook nests under body
  const payload = raw.payload || raw.data || raw;                    // envelope variants

  const status = String(payload.bookingStatus || payload.booking_status || raw.bookingStatus || '').toLowerCase();
  const action = String(raw.action || raw.eventType || raw.event || '').toLowerCase();
  const isCancel = ['cancel', 'cancelled', 'canceled'].includes(status)
    || ['deleted', 'cancelled', 'canceled', 'cancel'].includes(action);
  if (!isCancel) continue;   // ignore created/updated-but-not-cancelled events

  const appointment_id = payload.appointmentId || payload.appointment_id || payload.id
    || raw.appointmentId || raw.appointment_id || null;
  if (!appointment_id) continue;

  out.push({ json: { appointment_id } });
}
return out;
